<h2 class="wp-block-heading has-text-align-center has-primary-color has-text-color has-link-color has-caveat-brush-font-family" style="font-size:32px;font-style:normal;font-weight:100">Have Any Questions For Us?</h2>
<!-- /wp:heading -->

<!-- wp:paragraph {"className":"short-para-text","style":{"typography":{"fontStyle":"normal","fontWeight":"400","lineHeight":"1.8"},"elements":{"link":{"color":{"text":"var:preset|color|primary"}}},"spacing":{"padding":{"bottom":"var:preset|spacing|30"}}},"textColor":"primary","fontSize":"tiny","fontFamily":"rubik"} -->
<p class="short-para-text has-primary-color has-text-color has-link-color has-rubik-font-family has-tiny-font-size" style="padding-bottom:var(--wp--preset--spacing--30);font-style:normal;font-weight:400;line-height:1.8">We know that adopting or supporting a rescue pet comes with lots of questions, and we’re here to help every step of the way. Here you’ll find answers to some of the most common questions about our rescue, adoption process, and how you can get involved. If you don’t see your question here, please don’t hesitate to reach out—we’re always happy to help.</p>
<!-- /wp:paragraph -->

<!-- wp:paragraph {"align":"center"} -->
<p class="has-text-align-center">info@heartspawsministry.com</p>
<!-- /wp:paragraph -->

<!-- wp:columns {"verticalAlignment":"center"} -->
<div class="wp-block-columns are-vertically-aligned-center"><!-- wp:column {"verticalAlignment":"center","width":"25%"} -->
