<!-- wp:column {"className":"faq-right wow zoomInRight","style":{"spacing":{"blockGap":"var:preset|spacing|40"}}} -->
<div class="wp-block-column faq-right wow zoomInRight"><!-- wp:details {"showContent":true,"className":"faq-list","style":{"typography":{"fontStyle":"normal","fontWeight":"500"}}} -->
<details class="wp-block-details faq-list" style="font-style:normal;font-weight:500" open><summary>Do you adopt to first-time pet owners?</summary><!-- wp:paragraph {"placeholder":"Type / to add a hidden block","style":{"elements":{"link":{"color":{"text":"var:preset|color|primary"}}}},"textColor":"primary","fontSize":"tiny"} -->
<p class="has-primary-color has-text-color has-link-color has-tiny-font-size">Absolutely. We’re happy to work with first-time adopters and provide guidance, resources, and support to help set you up for success.</p>
<!-- /wp:paragraph --></details>
<!-- /wp:details -->

<!-- wp:details {"className":"faq-list","style":{"typography":{"fontStyle":"normal","fontWeight":"400"}}} -->
<details class="wp-block-details faq-list" style="font-style:normal;font-weight:400"><summary>Why is there an adoption fee?</summary><!-- wp:paragraph {"placeholder":"Type / to add a hidden block","style":{"elements":{"link":{"color":{"text":"var:preset|color|primary"}}},"typography":{"fontStyle":"normal","fontWeight":"400"}},"textColor":"primary","fontSize":"tiny"} -->
<p class="has-primary-color has-text-color has-link-color has-tiny-font-size" style="font-style:normal;font-weight:400">Adoption fees help cover medical care, food, housing, and rescue efforts for current and future animals. Your fee directly supports saving more lives.</p>
<!-- /wp:paragraph --></details>
<!-- /wp:details -->

<!-- wp:details {"className":"faq-list","style":{"typography":{"fontStyle":"normal","fontWeight":"500"}}} -->
<details class="wp-block-details faq-list" style="font-style:normal;font-weight:500"><summary>What if the adoption doesn’t work out?</summary><!-- wp:paragraph {"placeholder":"Type / to add a hidden block","style":{"elements":{"link":{"color":{"text":"var:preset|color|primary"}}}},"textColor":"primary","fontSize":"tiny"} -->
<p class="has-primary-color has-text-color has-link-color has-tiny-font-size">Our goal is a lifetime match, but we understand that sometimes things don’t work out. If needed, we ask that the pet be returned to us so we can ensure their continued safety and care.</p>
<!-- /wp:paragraph --></details>
<!-- /wp:details -->

<!-- wp:details {"className":"faq-list","style":{"typography":{"fontStyle":"normal","fontWeight":"500"}}} -->
<details class="wp-block-details faq-list" style="font-style:normal;font-weight:500"><summary>Do you adopt to apartments or renters?</summary><!-- wp:paragraph {"placeholder":"Type / to add a hidden block","style":{"elements":{"link":{"color":{"text":"var:preset|color|primary"}}}},"textColor":"primary"} -->
<p class="has-primary-color has-text-color has-link-color">Yes. We adopt to both homeowners and renters. If you rent, we may ask for landlord confirmation to ensure pets are allowed.</p>
<!-- /wp:paragraph --></details>
<!-- /wp:details -->

<!-- wp:details {"className":"faq-list","style":{"typography":{"fontStyle":"normal","fontWeight":"500"}}} -->
<details class="wp-block-details faq-list" style="font-style:normal;font-weight:500"><summary>What if my adopted pet needs medical care after adoption?</summary><!-- wp:paragraph {"placeholder":"Type / to add a hidden block","style":{"elements":{"link":{"color":{"text":"var:preset|color|primary"}}},"typography":{"fontStyle":"normal","fontWeight":"400"}},"textColor":"primary"} -->
<p class="has-primary-color has-text-color has-link-color" style="font-style:normal;font-weight:400">We provide full medical records and are always here to offer guidance. Any ongoing or future medical care after adoption is the responsibility of the adopter, unless otherwise specified.</p>
<!-- /wp:paragraph --></details>
<!-- /wp:details --></div>
<!-- /wp:column --></div>
<!-- /wp:columns --></div></div>
<!-- /wp:cover --></div>
